using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Data.Entity;
using System.Linq;
using System.Threading.Tasks;
using System.Web;
using System.Web.Mvc;

namespace ProductReviewsMvc.Controllers
{
    public class ReviewsController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        public async Task<ActionResult> Product(int id)
        {
            var product = await _db.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var model = new ProductReviewsViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAtUtc)
                    .Select(r => new ReviewDisplayViewModel
                    {
                        Id = r.Id,
                        UserName = r.UserName,
                        Rating = r.Rating,
                        CreatedAtUtc = r.CreatedAtUtc,
                        FormattedContent = ReviewHtmlSanitizer.Sanitize(r.Content)
                    })
                    .ToList()
            };

            return View("Product", model);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<ActionResult> Create(CreateReviewInputModel input)
        {
            if (!ModelState.IsValid)
            {
                return RedirectToAction("Product", new { id = input.ProductId });
            }

            var productExists = await _db.Products.AnyAsync(p => p.Id == input.ProductId);
            if (!productExists)
            {
                return HttpNotFound();
            }

            var review = new Review
            {
                ProductId = input.ProductId,
                UserName = string.IsNullOrWhiteSpace(input.UserName) ? "Anonymous" : input.UserName.Trim(),
                Rating = input.Rating,
                Content = input.Content ?? string.Empty,
                CreatedAtUtc = DateTime.UtcNow
            };

            _db.Reviews.Add(review);
            await _db.SaveChangesAsync();

            return RedirectToAction("Product", new { id = input.ProductId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }
    }

    public class ApplicationDbContext : DbContext
    {
        public ApplicationDbContext() : base("DefaultConnection")
        {
        }

        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }

        [Required]
        [StringLength(200)]
        public string Name { get; set; }

        public virtual ICollection<Review> Reviews { get; set; } = new List<Review>();
    }

    public class Review
    {
        public int Id { get; set; }

        [Required]
        public int ProductId { get; set; }

        [Required]
        [StringLength(100)]
        public string UserName { get; set; }

        [Required]
        [Range(1, 5)]
        public int Rating { get; set; }

        [Required]
        [StringLength(4000)]
        public string Content { get; set; }

        public DateTime CreatedAtUtc { get; set; }

        public virtual Product Product { get; set; }
    }

    public class ProductReviewsViewModel
    {
        public int ProductId { get; set; }
        public string ProductName { get; set; }
        public List<ReviewDisplayViewModel> Reviews { get; set; } = new List<ReviewDisplayViewModel>();
    }

    public class ReviewDisplayViewModel
    {
        public int Id { get; set; }
        public string UserName { get; set; }
        public int Rating { get; set; }
        public DateTime CreatedAtUtc { get; set; }
        public string FormattedContent { get; set; }
    }

    public class CreateReviewInputModel
    {
        [Required]
        public int ProductId { get; set; }

        [StringLength(100)]
        public string UserName { get; set; }

        [Required]
        [Range(1, 5)]
        public int Rating { get; set; }

        [Required]
        [StringLength(4000)]
        [AllowHtml]
        public string Content { get; set; }
    }

    public static class ReviewHtmlSanitizer
    {
        public static string Sanitize(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return string.Empty;
            }

            var encoded = HttpUtility.HtmlEncode(input);
            encoded = encoded.Replace("&lt;b&gt;", "<b>")
                             .Replace("&lt;/b&gt;", "</b>")
                             .Replace("&lt;strong&gt;", "<strong>")
                             .Replace("&lt;/strong&gt;", "</strong>")
                             .Replace("&lt;i&gt;", "<i>")
                             .Replace("&lt;/i&gt;", "</i>")
                             .Replace("&lt;em&gt;", "<em>")
                             .Replace("&lt;/em&gt;", "</em>")
                             .Replace("\r\n", "<br />")
                             .Replace("\n", "<br />");

            return encoded;
        }
    }
