/* Views/Reviews/Product.cshtml */
@model ProductReviewsMvc.Controllers.ProductReviewsViewModel

@{
    ViewBag.Title = Model.ProductName + " Reviews";
}

<h2>@Model.ProductName Reviews</h2>

<form method="post" action="@Url.Action("Create", "Reviews")">
    @Html.AntiForgeryToken()
    @Html.Hidden("ProductId", Model.ProductId)

    <div>
        <label for="UserName">Name</label>
        <input type="text" id="UserName" name="UserName" maxlength="100" />
    </div>

    <div>
        <label for="Rating">Rating</label>
        <select id="Rating" name="Rating">
            <option value="1">1</option>
            <option value="2">2</option>
            <option value="3">3</option>
            <option value="4">4</option>
            <option value="5" selected="selected">5</option>
        </select>
    </div>

    <div>
        <label for="Content">Review</label>
        <textarea id="Content" name="Content" rows="6" cols="60"></textarea>
        <p>Allowed formatting: &lt;b&gt;bold&lt;/b&gt;, &lt;i&gt;italic&lt;/i&gt;</p>
    </div>

    <button type="submit">Submit Review</button>
</form>

<hr />

@if (Model.Reviews != null && Model.Reviews.Any())
{
    foreach (var review in Model.Reviews)
    {
        <article style="margin-bottom:20px;">
            <header>
                <strong>@review.UserName</strong>
                <span> - Rating: @review.Rating/5</span>
                <div><small>@review.CreatedAtUtc.ToLocalTime().ToString("g")</small></div>
            </header>
            <div>@Html.Raw(review.FormattedContent)</div>
        </article>
    }
}
else
{
    <p>No reviews yet.</p>
}